import{_ as a,o,c as s,ag as i}from"./chunks/framework.BZohXCq9.js";const t="/assets/menu.CKwu5vzf.png",r="/assets/menu-sanciones.B99Ml0ir.png",n="/assets/freeze-staff.CoTuPjp5.png",d="/assets/freeze-player.wdLnGwOl.png",l="/assets/reportes.C4RmNreq.png",b=JSON.parse('{"title":"INFORMACIÓN:","description":"","frontmatter":{},"headers":[],"relativePath":"maxstaff/sanciones.md","filePath":"maxstaff/sanciones.md"}'),c={name:"maxstaff/sanciones.md"};function m(u,e,p,g,f,h){return o(),s("div",null,[...e[0]||(e[0]=[i('<h1 id="informacion" tabindex="-1">INFORMACIÓN: <a class="header-anchor" href="#informacion" aria-label="Permalink to &quot;INFORMACIÓN:&quot;">​</a></h1><blockquote><p>Acá verás información sobre como usar bien las sanciones, algunos archivos y demás, como siempre, tienes nuestro discord para cualquier consulta o duda <a href="https://discord.gg/Vr46JHm2kd" target="_blank" rel="noreferrer">https://discord.gg/Vr46JHm2kd</a></p></blockquote><h2 id="_1-sistema-visual-de-sanciones-gui" tabindex="-1">1. Sistema Visual de Sanciones (GUI) <a class="header-anchor" href="#_1-sistema-visual-de-sanciones-gui" aria-label="Permalink to &quot;1. Sistema Visual de Sanciones (GUI)&quot;">​</a></h2><blockquote><p>El comando principal para la moderación visual es <code>/sanction &lt;jugador&gt;</code> o usando el modo staff <code>/staff</code> cuando se ejecuta estos comandos se abre un panel donde se podrá ver el menú interactivo para poder inspeccionar al jugador.</p></blockquote><details><summary>Vista previa del menú</summary><p><img src="'+t+'" alt="alt text"></p><p><img src="'+r+'" alt="alt text"></p></details><ul><li><code>Información:</code> Muestra estadísticas del jugador (vida, hambre, IP, total de sanciones y si tiene cuentas vinculadas).</li><li><code>Estadísticas:</code> Información sobre el jugador UUID, tiempo jugado, sanciones totales.</li><li><code>Historial:</code> Abré un menú informativo mostrando todas las sanciones que tiene el usuario.</li><li><code>Sancionar:</code> En este apartado verás el menú más importante, con este podrás sancionar a los jugadores.</li><li><code>Multi-Cuentas:</code> Un apartado para ver todas las cuentas que tenga un jugador.</li><li><code>Inventario:</code> Te permite visualizar el inventario del jugador</li><li><code>Permisos:</code> Este es un menú adicional que permite ver todos los permisos del jugador</li></ul><h2 id="_2-formatos-de-tiempo" tabindex="-1">2. Formatos de Tiempo <a class="header-anchor" href="#_2-formatos-de-tiempo" aria-label="Permalink to &quot;2. Formatos de Tiempo&quot;">​</a></h2><p>Para sanciones temporales, utiliza las siguientes unidades:</p><ul><li><code>s</code>: segundos | <code>m</code>: minutos | <code>h</code>: horas | <code>d</code>: días | <code>w</code>: semanas</li><li>Ejemplo: <code>/ban ZkAleeJoo 30d Uso de hacks</code>.</li></ul><h2 id="_3-sistema-de-congelamiento-freeze-ss" tabindex="-1">3. Sistema de Congelamiento (Freeze/SS) <a class="header-anchor" href="#_3-sistema-de-congelamiento-freeze-ss" aria-label="Permalink to &quot;3. Sistema de Congelamiento (Freeze/SS)&quot;">​</a></h2><p>Diseñado para revisiones de pantalla o interrogatorios. Al usar <strong>/freeze jugador</strong>:</p><ul><li><code>Inmovilización:</code> El jugador no puede moverse, romper bloques ni abrir contenedores.</li><li><code>Efectos Visuales:</code> Se aplican automáticamente un efecto de ceguera y un casco de hielo (PACKED_ICE).</li></ul><details><summary>Vista previa del freeze</summary><p><img src="'+n+'" alt="alt text"></p><p><img src="'+d+'" alt="alt text"></p></details><h2 id="_4-historial-y-gestion-de-datos" tabindex="-1">4. Historial y Gestión de Datos <a class="header-anchor" href="#_4-historial-y-gestion-de-datos" aria-label="Permalink to &quot;4. Historial y Gestión de Datos&quot;">​</a></h2><ul><li><code>Ver Historial:</code> Usa <strong>/history [jugador]</strong> para ver el registro detallado de todas las sanciones pasadas, quién las aplicó y por qué motivo.</li><li><code>Limpiar Datos:</code> Solo los administradores pueden usar los subcomandos de <strong>/maxstaff</strong>: <ol><li><strong>/maxstaff reset [jugador] [tipo/ALL]</strong>: Elimina el historial completo.</li><li><strong>/maxstaff take [jugador] [tipo] [cantidad]</strong>: Elimina una cantidad específica de sanciones del registro.</li></ol></li></ul><h2 id="_5-sistema-de-reportes" tabindex="-1">5. Sistema de Reportes <a class="header-anchor" href="#_5-sistema-de-reportes" aria-label="Permalink to &quot;5. Sistema de Reportes&quot;">​</a></h2><p>Los jugadores pueden colaborar con la moderación usando el comando <strong>/report [jugador] [motivo]</strong>.</p><ul><li><code>Notificaciones:</code> El staff en línea recibirá una alerta inmediata con el nombre del acusador, el acusado y el motivo.</li><li><code>Protección:</code> Incluye un sistema de cooldown para evitar que los jugadores abusen del sistema de reportes.</li></ul><details><summary>Vista previa de los reportes</summary><p><img src="'+l+'" alt="alt text"></p></details>',19)])])}const v=a(c,[["render",m]]);export{b as __pageData,v as default};
